#include<bits/stdc++.h>
using namespace std;
int ans[5050],a[5050],b[5050];
bool vis[5050];
struct node
{
	int val,id;
	bool flag;
	bool operator<(const node&b)const
	{
		return val<b.val;
	}
	node(){}
	node(int a,int b,bool c):val(a),id(b),flag(c){}
};
vector<node> w;
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
		w.push_back(node(a[i],i,true));
	}
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&b[i]);
		w.push_back(node(b[i],i,false));
	}
	sort(w.begin(),w.end());
	int l=0,r=n+1;
	for(int i=0;i<n*2-1;i++)
	{
		if(vis[w[i].id])
		{
			continue;
		}
		if(w[i].flag)
		{
			ans[++l]=w[i].id;
		}
		else
		{
			ans[--r]=w[i].id;
		}
		vis[w[i].id]=true;
	}
	int tim1=0,tim2=0;
	for(int i=1;i<=n;i++)
	{
		tim1+=a[ans[i]];
		tim2=max(tim1,tim2);
		tim2+=b[ans[i]];
	}
	printf("%d\n",tim2);
	for(int i=1;i<=n;i++)
	{
		printf("%d ",ans[i]);
	}
	return 0;
}
